namespace ProductReviewApp.Services
{
    public interface IReviewSanitizer
    {
        string SanitizeReviewText(string input);
    }

    public class ReviewSanitizer : IReviewSanitizer
    {
        private static readonly HashSet<string> AllowedTags = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
        {
            "b", "i", "strong", "em"
        };

        public string SanitizeReviewText(string input)
        {
            if (string.IsNullOrWhiteSpace(input))
            {
                return string.Empty;
            }

            string encoded = HttpUtility.HtmlEncode(input);

            encoded = Regex.Replace(encoded, @"&lt;(b|strong)&gt;(.*?)&lt;/(b|strong)&gt;", 
                "<strong>$2</strong>", RegexOptions.IgnoreCase);
            
            encoded = Regex.Replace(encoded, @"&lt;(i|em)&gt;(.*?)&lt;/(i|em)&gt;", 
                "<em>$2</em>", RegexOptions.IgnoreCase);

            encoded = Regex.Replace(encoded, @"<(strong|em)>(.*?)</\1>", 
                m => {
                    string tag = m.Groups[1].Value;
                    string content = SanitizeNestedContent(m.Groups[2].Value);
                    return $"<{tag}>{content}</{tag}>";
                }, RegexOptions.IgnoreCase);

            return encoded;
        }

        private string SanitizeNestedContent(string content)
        {
            content = Regex.Replace(content, @"</?(?!strong|em)[^>]*>", string.Empty, RegexOptions.IgnoreCase);
            return content;
        }
    }
}

namespace ProductReviewApp.Controllers
{
    using ProductReviewApp.Models;
    using ProductReviewApp.Services;

    public class ProductController : Controller
    {
        private readonly ApplicationDbContext _context;
        private readonly IReviewSanitizer _reviewSanitizer;

        public ProductController()
        {
            _context = new ApplicationDbContext();
            _reviewSanitizer = new ReviewSanitizer();
        }

        public ProductController(ApplicationDbContext context, IReviewSanitizer reviewSanitizer)
        {
            _context = context;
            _reviewSanitizer = reviewSanitizer;
        }

        [HttpGet]
        public ActionResult Details(int id)
        {
            var product = _context.Products.Find(id);
            
            if (product == null)
            {
                return HttpNotFound();
            }

            var reviews = _context.Reviews
                .Where(r => r.ProductId == id)
                .OrderByDescending(r => r.CreatedDate)
                .ToList();

            var reviewViewModels = reviews.Select(r => new ReviewViewModel
            {
                Id = r.Id,
                UserName = HttpUtility.HtmlEncode(r.UserName),
                ReviewText = _reviewSanitizer.SanitizeReviewText(r.ReviewText),
                Rating = r.Rating,
                CreatedDate = r.CreatedDate
            }).ToList();

            var viewModel = new ProductReviewViewModel
            {
                Product = product,
                Reviews = reviewViewModels
            };

            return View(viewModel);
        }

        [HttpPost]
        [ValidateAntiForgeryToken]
        public ActionResult SubmitReview(int productId, string userName, string reviewText, int rating)
        {
            if (string.IsNullOrWhiteSpace(userName) || string.IsNullOrWhiteSpace(reviewText))
            {
                TempData["Error"] = "User name and review text are required.";
                return RedirectToAction("Details", new { id = productId });
            }

            if (rating < 1 || rating > 5)
            {
                TempData["Error"] = "Rating must be between 1 and 5.";
                return RedirectToAction("Details", new { id = productId });
            }

            if (userName.Length > 100)
            {
                TempData["Error"] = "User name is too long.";
                return RedirectToAction("Details", new { id = productId });
            }

            if (reviewText.Length > 5000)
            {
                TempData["Error"] = "Review text is too long.";
                return RedirectToAction("Details", new { id = productId });
            }

            var product = _context.Products.Find(productId);
            if (product == null)
            {
                return HttpNotFound();
            }

            var review = new Review
            {
                ProductId = productId,
                UserName = userName,
                ReviewText = reviewText,
                Rating = rating,
                CreatedDate = DateTime.UtcNow
            };

            _context.Reviews.Add(review);
            _context.SaveChanges();

            TempData["Success"] = "Review submitted successfully.";
            return RedirectToAction("Details", new { id = productId });
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                _context?.Dispose();
            }
            base.Dispose(disposing);
        }
    }
}